problem:
ในสามเหลี่ยมที่แสดง $n$ เป็นจำนวนเต็มบวก และ $\angle A > \angle B > \angle C$ มีค่าที่เป็นไปได้ของ $n$ กี่ค่า? [asy]
draw((0,0)--(1,0)--(.4,.5)--cycle);
label("$A$",(.4,.5),N); label("$B$",(1,0),SE); label("$C$",(0,0),SW);
label("$2n + 12$",(.5,0),S); label("$3n - 3$",(.7,.25),NE); label("$2n + 7$",(.2,.25),NW);
[/asy]

จงหาค่าของ $x$ ในแผนภาพ

[asy]

import olympiad;

draw((0,0)--(sqrt(3),0)--(0,sqrt(3))--cycle);

draw((0,0)--(-1,0)--(0,sqrt(3))--cycle);

label("8",(-1/2,sqrt(3)/2),NW);

label("$x$",(sqrt(3)/2,sqrt(3)/2),NE);

draw("$45^{\circ}$",(1.5,0),NW);

draw("$60^{\circ}$",(-0.9,0),NE);

draw(rightanglemark((0,sqrt(3)),(0,0),(sqrt(3),0),4));

[/asy]

แต่ละผลลัพธ์บนล้อหมุนที่อธิบายด้านล่างมีความน่าจะเป็นเท่ากัน หากคุณหมุนล้อ 4 ครั้งและนำผลลัพธ์เหล่านั้นมาเรียงเป็นจำนวนสี่หลัก โดยผลของการหมุนแต่ละครั้งจะสอดคล้องกับหลักที่ต่อเนื่องกันจากซ้ายไปขวา ความน่าจะเป็นที่คุณจะได้จำนวนสี่หลักที่หารด้วย 5 ลงตัวคือเท่าไร? แสดงคำตอบในรูปเศษส่วนธรรมดา

[asy]
draw(Circle((0,0),10));
draw((0,0)--(8.7,-5));
draw((0,0)--(-8.7,-5));
draw((0,0)--(0,10));
label("1",(7,7),SW);
label("3",(-7,7),SE);
label("2",(0,-2),S);
draw((0,0)--(3,5),Arrow);
[/asy]

จงหา $\cos C$ ในสามเหลี่ยมมุมฉากที่แสดงด้านล่าง


[asy]
pair A,B,C;
A = (0,0);
B = (6,0);
C = (0,8);
draw(A--B--C--A);
draw(rightanglemark(B,A,C,10));
label("$A$",A,SW);
label("$B$",B,SE);
label("$C$",C,N);
label("$10$",(B+C)/2,NE);
label("$6$",B/2,S);
[/asy]

รูปแสดงสามรูปสี่เหลียมจัตุรัสที่ไม่ทับซ้อนกันภายใน พื้นที่ของรูปสี่เหลียมจัตุรัสที่ระบายสีเท่ากับ 1 ตารางนิ้ว พื้นที่ของสี่เหลียมผืนผ้า $ABCD$ เท่ากับกี่ตารางนิ้ว

[asy]size(100);
pair A = (0,0), D = (3,0),C = (3,2),B = (0,2);
draw(A--B--C--D--cycle);
draw(A--(1,0)--(1,1)--(0,1)--cycle);
filldraw(B--(1,2)--(1,1)--(0,1)--cycle,gray(.6),black);
label("$A$",A,WSW);
label("$B$",B,WNW);
label("$C$",C,ENE);
label("$D$",D,ESE);[/asy]

พิจารณาตารางสี่เหลี่ยมผืนผ้าที่มีเส้นแนวตั้งและแนวนอนสร้างเป็นสี่เหลี่ยมผืนผ้าขนาด 4 by 3 จากจุด $A$ ไปยังจุด $B$ เธอสามารถเคลื่อนที่ได้เพียงไปทางขวา (R) หรือลง (D) เท่านั้น มีเส้นทางที่แตกต่างกันกี่แบบจากจุด $A$ ไปยังจุด $B$?

[asy]
unitsize(0.06inch);
draw((0,0)--(12,0)--(12,16)--(0,16)--cycle);
draw((4,0)--(4,16));
draw((8,0)--(8,16));
draw((0,4)--(12,4));
draw((0,8)--(12,8));
draw((0,12)--(12,12));
dot((0,16));
dot((12,0));
label("$A$",(0,16),NW);
label("$B$",(12,0),SE);
[/asy]

พื้นที่ที่ล้อมรั้วของลานเป็นบริเวณสี่เหลี่ยมผืนผ้าขนาด 15 × 12 ฟุต โดยมีสี่เหลี่ยมจัตุรัสขนาด 3 × 3 ฟุต ถูกตัดออก ดังที่แสดงในรูป พื้นที่ของบริเวณภายในรั้วเป็นกี่ตารางฟุต?

[asy]draw((0,0)--(16,0)--(16,12)--(28,12)--(28,0)--(60,0)--(60,48)--(0,48)--cycle);
label("15'",(30,48),N);
label("12'",(60,24),E);
label("3'",(16,6),W);
label("3'",(22,12),N);
[/asy]

จุดยอดของสามเหลี่ยมมุมฉาก $3 - 4 - 5$ เป็นจุดศูนย์กลางของวงกลมสามวงที่สัมผัสภายนอกกันตามที่แสดงในรูป ผลรวมของพื้นที่ของวงกลมทั้งสามนี้เท่าใด

[asy]unitsize(1cm);
draw(Circle((1.8,2.4),1),linewidth(0.7));
draw(Circle((0,0),2),linewidth(0.7));
draw(Circle((5,0),3),linewidth(0.7));
draw((0,0)--(5,0)--(1.8,2.4)--cycle,linewidth(0.7));
label("$A$",(1.8,2.4),N);
label("$B$",(0,0),SW);
label("$C$",(5,0),E);
label("5",(2.5,0),S);
label("4",(3.4,1.2),NE);
label("3",(0.9,1.2),NW);
[/asy]

วงกลมที่มีรัศมี 4 เซนติเมตร สัมผัสกับสามด้านของสี่เหลี่ยมผืนผ้าดังที่แสดงในรูป พื้นที่ของสี่เหลี่ยมผืนผ้าเป็นสองเท่าของพื้นที่วงกลม ความยาวของด้านที่ยาวกว่าของสี่เหลี่ยมผืนผ้าเป็นเท่าไหร่ (หน่วยเป็นเซนติเมตร) แสดงคำตอบในรูปของ $\pi$

[asy]
import graph;
draw((0,0)--(30,0)--(30,20)--(0,20)--cycle);
draw(Circle((10,10),10));
[/asy]

ในแผนภาพ $AB$ เป็นส่วนของเส้นตรงในแนวนอน และ $CD$ เป็นส่วนของเส้นตรงในแนวตั้งโดยที่ $C$ อยู่บน $AB$ ส่วนของเส้นตรง $CE$ ทำมุมกับ $AB$ เส้นตรง $AB$ และ $CD$ ตัดกันที่จุด $C$ กำหนดให้ $\angle ECD = 63^\circ$ และ $AB$ ตั้งฉากกับ $CD$ จงหาค่าของ $x$ ถ้า $x$ คือมุมที่เกิดจาก $CE$ กับ $AB$

[asy]
draw((0,0)--(10,0),black+linewidth(1));
draw((4,0)--(4,8),black+linewidth(1));
draw((4,0)--(3.5,0)--(3.5,0.5)--(4,0.5)--cycle,black+linewidth(1));
draw((4,0)--(9,7),black+linewidth(1));
label("$A$",(0,0),W);
label("$B$",(10,0),E);
label("$x^\circ$",(4.75,2.25));
label("$63^\circ$",(5.5,0.75));
label("$C$",(4,0),S);
label("$D$",(4,8),N);
label("$E$",(9,7),NE);
[/asy]

เส้นตรง $y = b-x$ โดยที่ $0 < b < 4$ ตัดแกน $y$ ที่จุด $P$ และตัดเส้นตรง $x=4$ ที่จุด $S$ ถ้าอัตราส่วนของพื้นที่สามเหลี่ยม $QRS$ ต่อพื้นที่สามเหลี่ยม $QOP$ เท่ากับ 9:25 จงหาค่า $b$ แสดงคำตอบเป็นทศนิยมที่ใกล้เคียงที่สุดในหลักสิบ

[asy]
draw((0,-3)--(0,5.5),Arrows);
draw((4,-3.5)--(4,5),Arrows);

draw((-2,0)--(6,0),Arrows);

draw((-2,4.5)--(6,-3.5),Arrows);

dot((0,0));
dot((2.5,0));
dot((4,0));
dot((4,-1.5));
dot((0,2.5));

label("O",(0,0),SW);
label("P",(0,2.5),NE);
label("Q",(2.5,0),NE);
label("R",(4,0),NE);
label("S",(4,-1.5),SW);

label("$y$-axis",(0,5.5),N);
label("$x=4$",(4,5),N);
label("$x$-axis",(6,0),E);
label("$y=b-x$",(6,-3.5),SE);
[/asy]

จุด $D$ และ $E$ ถูกเลือกบนด้าน $BC$ ของสามเหลี่ยม $ABC$ โดยที่ $E$ อยู่ระหว่าง $B$ และ $D$ และ $BE=1$, $ED=DC=3$ ถ้า $\angle BAD=\angle EAC=90^\circ$ พื้นที่ของ $ABC$ สามารถเขียนได้ในรูป $\tfrac{p\sqrt q}r$ โดยที่ $p$ และ $r$ เป็นจำนวนเต็มบวกที่เป็นจำนวนเฉพาะสัมพัทธ์กัน และ $q$ เป็นจำนวนเต็มบวกที่ไม่หารด้วยกำลังสองของจำนวนเฉพาะใดๆ ลงตัว จงหา $p+q+r$

[asy]
import olympiad;
size(200);
defaultpen(linewidth(0.7)+fontsize(11pt));
pair D = origin, E = (3,0), C = (-3,0), B = (4,0);
path circ1 = arc(D,3,0,180), circ2 = arc(B/2,2,0,180);
pair A = intersectionpoint(circ1, circ2);
draw(E--A--C--B--A--D);
label(" $A$ ",A,N);
label(" $B$ ",B,SE);
label(" $C$ ",C,SW);
label(" $D$ ",D,S);
label(" $E$ ",E,S);
[/asy]

จำนวนเกมที่ชนะของทีมเบสบอลห้าทีมแสดงในกราф แต่ชื่อทีมหายไป นี่คือเบาะแสบางอย่าง:

1. ทีมสิงโตชนะเกมมากกว่าทีมเหยี่ยว
2. ทีมนักรบชนะเกมมากกว่าทีมจิ้งจอก แต่น้อยกว่าทีมอัศวิน
3. ทีมจิ้งจอกชนะมากกว่า 24 เกม

ทีมนักรบชนะกี่เกม? [asy]
size(150);
defaultpen(linewidth(0.7pt)+fontsize(8));

int i = 1;

draw((0,i*5)--(60,i*5)); ++i;

fill(shift(12,0)*((4,0)--(4,11)--(8,11)--(8,0)--cycle),blue);
draw(shift(12,0)*((4,0)--(4,11)^^(8,0)--(8,11)));
draw((0,i*5)--(60,i*5)); ++i;

fill((4,0)--(4,18)--(8,18)--(8,0)--cycle,blue);
draw((4,0)--(4,18));
draw((8,0)--(8,18));

for(i = 3; i <= 4; ++i)
{
draw((0,i*5)--(60,i*5));
}

fill(shift(24,0)*((4,0)--(4,27)--(8,27)--(8,0)--cycle),blue);
draw(shift(24,0)*((4,0)--(4,27)^^(8,0)--(8,27)));
draw((0,i*5)--(60,i*5)); ++i;

fill(shift(36,0)*((4,0)--(4,33)--(8,33)--(8,0)--cycle),blue);
draw(shift(36,0)*((4,0)--(4,33)^^(8,0)--(8,33)));
draw((0,i*5)--(60,i*5)); ++i;

fill(shift(48,0)*((4,0)--(4,40)--(8,40)--(8,0)--cycle),blue);
draw(shift(48,0)*((4,0)--(4,40)^^(8,0)--(8,40)));
draw((0,i*5)--(60,i*5));
draw((0,i*5)--(60,i*5));

xaxis(Bottom,0,60, RightTicks(" ", N=5, n=1, Size=2));
yaxis(Left,0,45, LeftTicks(Step=5, Size=2));
yaxis(Right,0,45);

label("ผลการแข่งขันเบสบอล",(30,50));
label(rotate(90)*"จำนวนครั้งที่ชนะ",(-10,22.5));
label("ทีม",(30,-10));
for(i = 0; i < 5; ++i)
{
label("?",(6+12*i,-4));
}
[/asy]

สามเหลี่ยมหน้าจั่ว $ABE$ มีพื้นที่ 100 ตารางนิ้ว ถูกตัดด้วย $\overline{CD}$ ให้เป็นคางหมูหน้าจั่วและสามเหลี่ยมหน้าจั่วที่เล็กกว่า พื้นที่ของคางหมูคือ 75 ตารางนิ้ว ถ้าความสูงของสามเหลี่ยม $ABE$ จากจุด $A$ คือ 20 นิ้ว ความยาวของ $\overline{CD}$ เป็นกี่นิ้ว?

[asy]
draw((-9,0)--(0,24)--(9,0)--cycle);
draw((-6,8)--(6,8));
label("$A$",(0,24),N);
label("$B$",(-9,0),W);
label("$C$",(-6,8),NW);
label("$D$",(6,8),NE);
label("$E$",(9,0),E);
[/asy]

กรอกตัวเลขลงในช่องสี่เหลี่ยมด้านล่างให้ผลรวมของตัวเลขในช่องที่ติดต่อกัน 3 ช่อง เท่ากับ $2005$ จงหาตัวเลขที่ต้องใส่ในช่องซ้ายสุด

[asy]
size(300);
label("999",(2.5,.5));
label("888",(7.5,.5));

draw((0,0)--(9,0));
draw((0,1)--(9,1));
for (int i=0; i<=9; ++i)
{
draw((i,0)--(i,1));
}
[/asy]

ในสามเหลี่ยมมุมฉาก $ABC$ ที่กำหนดให้ โดยมุมที่จุด $B$ เป็นมุมฉาก (90 องศา) จุด $D$ อยู่บนด้าน $BC$ อัตราส่วนของ $BD$ ต่อ $DC$ เท่ากับ $5$ ต่อ $2$ พื้นที่ของ $\triangle ABD$ เท่ากับ $35$ ตารางเซนติเมตร คำนวณหาพื้นที่ของ $\triangle ADC$
[asy] size(85); defaultpen(linewidth(1)+fontsize(10));

pair A = (0,5.5), B=(0,0), D = (3.5,0), C = (5,0);

draw(A--B--C--A--D); label("A",A,N); label("B",B,S); label("C",C,S); label("D",D,S);
draw(rightanglemark(A,B,C,8),linewidth(0.7));
[/asy]

บ็อบทอยลูกเต๋าหกหน้าที่ยุติธรรมทุกเช้า หากบ็อบทอยได้จำนวนประกอบ เขาจะกินซีเรียลหวาน หากเขาทอยได้จำนวนเฉพาะ เขาจะกินซีเรียลไม่หวาน หากเขาทอยได้ 1 เขาจะทอยใหม่อีกครั้ง ในปีปกติ (365 วัน) ค่าคาดหวังของผลต่างระหว่างจำนวนวันที่บ็อบกินซีเรียลไม่หวานกับจำนวนวันที่เขากินซีเรียลหวานคือเท่าใด [asy]
import olympiad; import geometry; size(50);

defaultpen(linewidth(0.8));
draw(unitsquare);
draw((0,1)--(0.5,1.5)--(1.5,1.5)--(1.5,0.5)--(1,0)^^(1.5,1.5)--(1,1));
dot((0.3,0.2)); dot((0.7,0.2));
dot((0.3,0.5)); dot((0.7,0.5));
dot((0.3,0.8)); dot((0.7,0.8));
dot((1.125,0.375)); dot((1.25,0.75)); dot((1.375,1.125));
dot((0.5,0.5/3 + 1)); dot((1.0,4/3));
[/asy]

กำหนดให้ $\cos R = \frac{5}{13}$ ในสามเหลี่ยมด้านล่าง จงหา $QS$

[asy]
pair Q,R,S;
S = (0,0);
Q = (sqrt(144),0);
R = (sqrt(144),-5);
draw(S--Q--R--S);
draw(rightanglemark(S,Q,R,13));
label("$S$",S,NW);
label("$Q$",Q,NE);
label("$R$",R,SE);
label("$13$",(R+S)/2,SW);
