ในสามเหลี่ยมมุมฉาก $XYZ$ ที่แสดงด้านล่าง $\cos{Z} = \frac{12\sqrt{221}}{221}$ จงหา $XZ$.
[asy]
draw((0,0)--(9,0)--(0,12)--cycle,black+linewidth(1));
draw(rightanglemark((9,0),(0,0),(0,12),20),black+linewidth(1));
label("$X$",(0,0),W);
label("$Y$",(9,0),E);
label("$Z$",(0,12),N);
label("$\sqrt{221}$",(9,0)--(0,12),NE);
