พิจารณาตารางมหัศจรรย์ที่ผลรวมของตัวเลขสามตัวในแถว คอลัมน์ หรือเส้นทแยงมุมใดๆ จะเท่ากัน ด้านล่างเป็นส่วนหนึ่งของตารางมหัศจรรย์ที่มีค่าบางตัวที่ทราบแล้ว จงหาค่า $y$
[asy]
size(2cm);
for (int i=0; i<=3; ++i) draw((i,0)--(i,3)^^(0,i)--(3,i));
label("$y$",(0.5,2.5));label("$23$",(1.5,2.5));
label("$104$",(2.5,2.5));label("$5$",(0.5,1.5));
