แอนสร้างบันได $3$ ขั้นโดยใช้ไม้จิ้มฟัน $18$ อันดังแสดงในรูป เธอต้องเพิ่มไม้จิ้มฟันอีกกี่อันเพื่อให้เป็นบันได $5$ ขั้น
[asy]
size(150);
defaultpen(linewidth(0.8));
path h = ellipse((0.5,0),0.45,0.015), v = ellipse((0,0.5),0.015,0.45);
for(int i=0;i<=2;i=i+1) {
for(int j=0;j<=3-i;j=j+1) {
filldraw(shift((i,j))*h,black);
filldraw(shift((j,i))*v,black);
}
}
[/asy]

จงหาความยาว $AB$ ในสามเหลี่ยมด้านล่างนี้

[asy]
unitsize(1inch);
pair A,B,C;
A = (0,0);
B = (1,0);
C = (0.5,sqrt(3)/2);
draw (A--B--C--A,linewidth(0.9));
draw(rightanglemark(B,A,C,3));
label("$A$",A,S);
label("$B$",B,S);
label("$C$",C,N);
label("$18$", (A+C)/2,W);
label("$30^\circ$", (0.3,0),N);
[/asy]

สมมติว่า $\cos S = 0.5$ ในสามเหลี่ยมมุมฉากที่ $SP = 10$ จงหา $SR$

[asy]
pair S,P,R;
S = (0,0);
P = (10,0);
R = (0,10*tan(acos(0.5)));
draw(S--P--R--S);
draw(rightanglemark(S,P,R,18));
label("$S$",S,SW);
label("$P$",P,SE);
label("$R$",R,N);
label("$10$",P/2,S);
[/asy]

เป้าหมายด้านล่างประกอบด้วยวงกลมศูนย์กลางร่วมที่มีเส้นผ่านศูนย์กลาง $4$, $8$, $12$, $16$, และ $20$ พื้นที่ของบริเวณสีเข้มเท่ากับ $n\pi$ จงหา $n$

[asy]
size(150);
defaultpen(linewidth(0.8));
int i;
for(i=5;i>=1;i=i-1)
{
if (floor(i/2)==i/2)
{
filldraw(circle(origin,4*i),white);
}
else
{
filldraw(circle(origin,4*i),red);
}
