ในแผนภาพ สามเหลี่ยมหน้าจั่วที่เหมือนกันสองคู่ถูกตัดออกจากสี่เหลี่ยมจัตุรัส $ABCD$ ทำให้เหลือสี่เหลี่ยมผืนผ้า $PQRS$ พื้นที่ทั้งหมดที่ถูกตัดออกเท่ากับ $200 \text{ m}^2$ ความยาวของ $PR$ เท่ากับเท่าไหร่ (หน่วยเป็นเมตร) [asy]
size(5cm);

pair a = (0, 1); pair b = (1, 1); pair c = (1, 0); pair d = (0, 0);
